import json

NEW_INTRO = {
"52": "Основные понятия: Молекулярно-кинетическая теория (МКТ) объясняет макроскопические свойства вещества (давление, температуру, объём) через микроскопическое хаотическое движение и взаимодействие огромного числа молекул. Её три основных положения: 1) вещество состоит из отдельных частиц (молекул, атомов); 2) эти частицы находятся в непрерывном хаотическом (тепловом) движении, интенсивность которого связана с температурой; 3) между частицами действуют силы притяжения и отталкивания, зависящие от расстояния между ними. МКТ — мост между микромиром отдельных молекул и макроскопическими, измеримыми в эксперименте величинами.",
"53": "Основные понятия: Основное уравнение МКТ связывает макроскопическую величину — давление газа — с микроскопическими характеристиками молекул: их массой, концентрацией (числом в единице объёма) и средней кинетической энергией хаотического движения. Физический смысл в том, что давление газа на стенку сосуда — это результат огромного числа ударов молекул о стенку в единицу времени, и чем интенсивнее движутся молекулы (выше их кинетическая энергия) и чем их больше, тем сильнее суммарный «напор» на стенку. Это уравнение — первый мостик, напрямую связывающий температуру (через среднюю кинетическую энергию молекул) с измеримым давлением газа.",
"54": "Основные понятия: Уравнение Менделеева-Клапейрона (уравнение состояния идеального газа) связывает воедино четыре макроскопических параметра газа — давление, объём, температуру и количество вещества, — позволяя по трём известным величинам найти четвёртую для любого состояния идеального газа. Идеальный газ — это модель, в которой пренебрегают собственным объёмом молекул и силами взаимодействия между ними (кроме упругих столкновений), что хорошо приближает поведение реальных газов при не слишком высоких давлениях и не слишком низких температурах. Это уравнение — фундаментальный инструмент для расчёта поведения газов, включая газы в лёгких и растворённые в крови.",
"55": "Основные понятия: Изопроцессы — это частные случаи изменения состояния газа, при которых один из макроскопических параметров остаётся постоянным: изотермический процесс (постоянная температура, закон Бойля-Мариотта — давление обратно пропорционально объёму), изобарный (постоянное давление, закон Гей-Люссака — объём пропорционален температуре) и изохорный (постоянный объём, закон Шарля — давление пропорционально температуре). Все эти частные газовые законы являются следствиями общего уравнения Менделеева-Клапейрона при фиксации одного из параметров и помогают наглядно понять, как связаны между собой давление, объём и температура газа.",
"56": "Основные понятия: Лёгочные объёмы и ёмкости — это физиологические величины, описывающие количество воздуха, которое может содержаться или перемещаться в лёгких при дыхании, и они напрямую связаны с газовыми законами: дыхательный объём (объём одного спокойного вдоха/выдоха), резервные объёмы вдоха и выдоха (дополнительный воздух, который можно вдохнуть или выдохнуть сверх обычного), остаточный объём (воздух, остающийся в лёгких после максимального выдоха). Ёмкости — это суммы нескольких объёмов (например, жизненная ёмкость лёгких — сумма дыхательного объёма и обоих резервных объёмов), характеризующие функциональные возможности дыхательной системы. Эти величины измеряются методом спирометрии и являются важным диагностическим показателем состояния дыхательной системы.",
"57": "Основные понятия: Термодинамическая система — это выделенная (мысленно или физически) часть материального мира, отделённая от окружающей среды реальной или воображаемой границей, поведение которой изучается методами термодинамики. По характеру обмена с окружающей средой системы делятся на изолированные (не обмениваются с окружением ни веществом, ни энергией), закрытые (обмениваются энергией, но не веществом) и открытые (обмениваются и энергией, и веществом). Живые организмы — классический пример открытых систем: они непрерывно обмениваются с окружающей средой и веществом (питание, дыхание, выделение), и энергией (тепло), что принципиально отличает их термодинамическое поведение от изолированных или закрытых систем.",
"58": "Основные понятия: Экстенсивные параметры термодинамической системы пропорциональны количеству вещества (массе, числу молекул) в системе — например, масса, объём, внутренняя энергия, энтропия: если мысленно разделить систему пополам, каждая половина будет иметь ровно половину значения экстенсивного параметра. Интенсивные параметры не зависят от количества вещества и остаются одинаковыми в любой части однородной системы — например, температура, давление, концентрация: разделив систему пополам, в каждой половине температура останется той же. Различение экстенсивных и интенсивных величин важно для правильной формулировки термодинамических законов и для понимания того, какие величины можно складывать при объединении систем, а какие — нет.",
"59": "Основные понятия: Обратимый процесс — это идеализированный процесс, который может быть проведён в противоположном направлении через ту же последовательность промежуточных равновесных состояний, не оставляя никаких изменений ни в самой системе, ни в окружающей среде; такой процесс должен происходить бесконечно медленно, чтобы система всё время оставалась в состоянии, близком к равновесию. Необратимый процесс — это реальный процесс, который самопроизвольно идёт только в одном направлении и не может быть в точности «прокручен назад» без затраты дополнительной энергии извне; все реальные процессы в природе (включая биологические) необратимы. Понятие обратимости тесно связано с энтропией: обратимые процессы не увеличивают суммарную энтропию системы и окружения, тогда как необратимые процессы всегда её увеличивают.",
"60": "Основные понятия: Внутренняя энергия идеального газа — это суммарная кинетическая энергия хаотического (теплового) движения всех его молекул (для идеального газа потенциальная энергия взаимодействия молекул считается равной нулю, поскольку взаимодействием пренебрегают). Ключевая особенность идеального газа в том, что его внутренняя энергия зависит только от температуры и количества вещества, но не зависит от объёма или давления — поэтому при изотермическом процессе (постоянной температуре) внутренняя энергия идеального газа не меняется, даже если объём и давление сильно изменились. Это делает температуру прямой мерой средней кинетической энергии молекул и, соответственно, внутренней энергии газа.",
"61": "Основные понятия: Первое начало термодинамики — это закон сохранения энергии применительно к тепловым процессам: изменение внутренней энергии системы равно сумме теплоты, переданной системе, и работы, совершённой над системой (или разности между полученной теплотой и работой, совершённой самой системой). Для изолированной системы (нет обмена ни теплом, ни работой с окружением) внутренняя энергия остаётся строго постоянной; для закрытой системы (обмен энергией есть, но нет обмена веществом) внутренняя энергия может меняться за счёт теплообмена и совершения работы. Физический смысл первого начала в том, что энергию нельзя ни создать из ничего, ни уничтожить — она лишь переходит из одной формы в другую или передаётся от одной системы к другой.",
"62": "Основные понятия: Первое начало термодинамики для живых организмов формулируется так же, как и для любой термодинамической системы: изменение внутренней энергии организма равно теплоте, полученной (или отданной) организмом, и работе, совершённой над организмом или самим организмом. Особенность живых организмов как открытых систем в том, что «приход» энергии обеспечивается не столько теплом извне, сколько энергией пищи (химической энергией питательных веществ), которая в организме превращается во внутреннюю работу (сокращение мышц, синтез веществ, поддержание градиентов) и в конечном счёте — в тепло, рассеиваемое в окружающую среду. Таким образом, первое начало термодинамики позволяет составить энергетический баланс организма: энергия пищи расходуется на совершаемую работу и на теплоотдачу.",
"63": "Основные понятия: В организме совершаются разные виды работы: механическая (сокращение мышц, работа сердца, дыхательные движения), химическая (синтез сложных молекул из более простых, поддержание неравновесных концентраций веществ), электрическая (создание и поддержание трансмембранных разностей потенциалов, проведение нервных импульсов), осмотическая (перенос веществ против градиента концентрации) и другие. КПД организма — это отношение полезной (совершённой) работы к общему количеству энергии, полученной с пищей; поскольку значительная часть энергии пищи неизбежно рассеивается в виде тепла, КПД организма относительно невысок и обычно не превышает 20–25%, что согласуется со вторым началом термодинамики, ограничивающим эффективность превращения энергии в работу.",
"64": "Основные понятия: Организм поддерживает постоянную температуру тела за счёт баланса между теплопродукцией (в основном за счёт обмена веществ) и теплоотдачей во внешнюю среду, которая происходит четырьмя основными физическими способами: теплопроведением (прямой контакт с более холодными предметами), конвекцией (перенос тепла движущимся воздухом или жидкостью у поверхности тела), излучением (испускание инфракрасных электромагнитных волн нагретой поверхностью тела) и испарением (затрата тепла на испарение пота или влаги с поверхности кожи и слизистых, например при дыхании). Соотношение вкладов этих механизмов существенно зависит от условий окружающей среды — при высокой температуре воздуха, близкой к температуре тела, основным механизмом теплоотдачи становится испарение, поскольку теплопроведение и излучение при малой разнице температур становятся неэффективными.",
"65": "Основные понятия: Основной обмен — это минимальное количество энергии, необходимое организму для поддержания жизненно важных функций (работы сердца, дыхания, поддержания температуры тела, работы нервной системы и т.д.) в состоянии полного покоя, натощак, при комфортной температуре среды, то есть без затрат энергии на физическую активность, переваривание пищи или терморегуляцию сверх минимума. Основной обмен зависит от массы тела, площади поверхности тела, возраста, пола и гормонального статуса (в частности, от уровня гормонов щитовидной железы) и обычно оценивается через измерение количества потребляемого кислорода или выделяемого тепла (методы прямой и непрямой калориметрии). Показатель основного обмена важен клинически, поскольку его отклонения от нормы могут указывать на нарушения обмена веществ или эндокринной функции.",
"66": "Основные понятия: Энтропия — это физическая величина, характеризующая степень неупорядоченности (хаотичности) состояния системы, а также меру необратимого рассеивания энергии: чем более хаотично распределены энергия и вещество в системе, тем выше её энтропия. С термодинамической точки зрения энтропия связана с количеством теплоты, полученной или отданной системой при обратимом процессе, отнесённым к температуре, при которой этот теплообмен происходит. Энтропия — одна из немногих термодинамических величин, которая не сохраняется в изолированных системах, а самопроизвольно возрастает при любом реальном (необратимом) процессе, что и составляет содержание второго начала термодинамики.",
"67": "Основные понятия: Полную внутреннюю энергию системы можно условно разделить на свободную энергию — ту часть энергии, которая может быть превращена в полезную работу при данных условиях, — и связанную энергию — ту часть, которая уже «обесценена» (рассеяна, разупорядочена) и не может быть превращена в работу, а лишь переходит в тепло. Связанная энергия прямо пропорциональна произведению энтропии системы на абсолютную температуру: чем выше энтропия (степень хаоса), тем больше доля энергии, «запертой» в неработоспособной форме. Это разделение подчёркивает, что для живых и технических систем важна не только суммарная энергия, но и её качество — способность совершать полезную работу.",
"68": "Основные понятия: Термодинамический смысл энтропии заключается в том, что она количественно отражает необратимость реальных процессов и направление, в котором самопроизвольно протекают процессы в изолированной системе: энтропия изолированной системы либо остаётся постоянной (при обратимых процессах), либо возрастает (при необратимых, то есть при всех реальных процессах), но никогда не убывает. Это делает энтропию своего рода «стрелой времени» в физике: направление возрастания энтропии совпадает с направлением течения реальных, необратимых процессов, отличая прошлое от будущего на макроскопическом уровне, хотя отдельные молекулярные взаимодействия обратимы во времени.",
"69": "Основные понятия: Статистический смысл энтропии, раскрытый Больцманом, связывает энтропию с числом микроскопических способов (микросостояний), которыми может быть реализовано данное макроскопическое состояние системы: чем больше таких способов, тем выше энтропия состояния. Формула Больцмана показывает, что энтропия — это мера «вероятности» состояния: упорядоченные состояния (например, все молекулы газа собраны в одном углу сосуда) можно реализовать очень малым числом способов и поэтому они статистически крайне маловероятны, тогда как хаотичные, равномерно распределённые состояния реализуются огромным числом способов и потому статистически наиболее вероятны. Именно поэтому системы самопроизвольно эволюционируют в сторону более вероятных (более хаотичных, с большей энтропией) состояний — не потому, что этого «требует» какой-то закон, а просто потому, что таких состояний неизмеримо больше.",
"70": "Основные понятия: Второе начало термодинамики для изолированных систем утверждает, что энтропия изолированной системы (не обменивающейся веществом и энергией с окружением) не может самопроизвольно убывать — она либо остаётся постоянной (в идеальных обратимых процессах), либо возрастает (во всех реальных, необратимых процессах), стремясь к максимуму, соответствующему состоянию термодинамического равновесия. Этот закон задаёт направление самопроизвольного протекания процессов в природе: тепло самопроизвольно переходит от горячего тела к холодному, а не наоборот, газ самопроизвольно расширяется в пустоту, а не сжимается сам собой — все эти процессы увеличивают энтропию. Второе начало термодинамики — фундаментальное ограничение на то, какие процессы вообще возможны в природе без затраты энергии извне.",
"71": "Основные понятия: Термодинамическое равновесие — это состояние системы, в котором все макроскопические параметры (температура, давление, концентрация и др.) одинаковы во всех частях системы и не меняются со временем при отсутствии внешних воздействий; в этом состоянии энтропия изолированной системы достигает своего максимального возможного значения. Достигнув равновесия, система самопроизвольно не может из него выйти без внешнего вмешательства — любые внутренние процессы (диффузия, теплообмен, химические реакции) в равновесной системе прекращаются, поскольку все движущие силы (градиенты температуры, концентрации, давления) исчезают. Живые организмы принципиально не находятся в термодинамическом равновесии с окружающей средой — их существование как раз и требует постоянного поддержания неравновесного состояния за счёт непрерывного притока энергии и вещества.",
"72": "Основные понятия: Живые организмы — открытые системы, находящиеся в состоянии, далёком от термодинамического равновесия, поэтому прямое применение второго начала термодинамики (которое сформулировано для изолированных систем) к ним требует уточнения. Организм поддерживает низкую энтропию внутри себя (высокую упорядоченность структур и процессов) не за счёт нарушения второго начала, а за счёт того, что он выделяет во внешнюю среду больше энтропии, чем производит внутри себя за счёт необратимых процессов метаболизма — суммарная энтропия организма и окружающей среды в целом всё равно возрастает, как того требует второе начало для системы «организм + среда». Именно постоянный обмен веществом и энергией с окружением (питание, дыхание, выделение) позволяет живой системе оставаться высокоупорядоченной, «экспортируя» энтропию наружу.",
"73": "Основные понятия: Продукция энтропии — это количество энтропии, производимое внутри самой системы за единицу времени за счёт необратимых процессов, протекающих в ней (химических реакций, диффузии, теплопроводности, трения); эта величина всегда положительна для любых реальных, необратимых процессов, согласно второму началу термодинамики. Поток энтропии — это энтропия, переносимая через границы системы вместе с потоками вещества и энергии (тепла), которая может быть как положительной (энтропия поступает в систему), так и отрицательной (энтропия выводится из системы во внешнюю среду). Общее изменение энтропии открытой системы (такой как живой организм) складывается из суммы внутренней продукции энтропии (всегда ≥ 0) и потока энтропии через границы (может быть отрицательным) — именно за счёт отрицательного потока энтропии (выведения её в окружающую среду) организм способен поддерживать и даже увеличивать свою внутреннюю упорядоченность.",
"74": "Основные понятия: Теорема Пригожина относится к стационарным состояниям открытых систем, находящихся вблизи термодинамического равновесия: она утверждает, что в таком стационарном состоянии скорость производства энтропии внутри системы за счёт необратимых процессов минимальна из всех возможных состояний при данных внешних ограничениях (в отличие от изолированной системы, которая стремится к максимуму энтропии, открытая система вблизи равновесия стремится к минимуму скорости её производства). Эта теорема — важный принцип неравновесной термодинамики, объясняющий, почему живые системы и другие открытые системы способны поддерживать стабильные, устойчивые стационарные состояния, эффективно минимизируя рассеивание энергии при заданных условиях обмена с окружающей средой.",
}

with open("physics_questions.json", "r", encoding="utf-8") as f:
    data = json.load(f)

changed = 0
for k, new_intro in NEW_INTRO.items():
    a = data[k]["answer"]
    parts = a.split("\n\n", 1)
    rest = parts[1] if len(parts) > 1 else ""
    if rest:
        data[k]["answer"] = new_intro + "\n\n" + rest
    else:
        data[k]["answer"] = new_intro
    changed += 1

with open("physics_questions.json", "w", encoding="utf-8") as f:
    json.dump(data, f, ensure_ascii=False, indent=2)

print("changed:", changed)
